const query = $input.first().json.query || {};
const tenantId = query.tenant || 'default';

const staticData = $getWorkflowStaticData('global');
if (!staticData.configs) staticData.configs = {};

const config = staticData.configs[tenantId] || getDefaultConfig(tenantId);

function getDefaultConfig(id) {
  return {
    tenant_id: id,
    bot: {
      name: 'Flora',
      avatar_url: '',
      avatar_fallback: '🌿',
      welcome_message: {
        en: "Hi! I'm Flora 🌿 How can I help you with your plants today?",
        es: '¡Hola! Soy Flora 🌿 ¿En qué puedo ayudarte con tus plantas hoy?'
      }
    },
    appearance: {
      colors: {
        primary: '#2D5A27', secondary: '#4A7C43', accent: '#8FBC8F',
        user_bubble: '#2D5A27', bot_bubble: '#F0F5EF',
        background: '#FFFFFF', text: '#333333'
      },
      typography: { font_family: 'system-ui', font_size: '14px' },
      borders: { radius: '16px', style: 'rounded' },
      fab: { shape: 'circle', size: 'md', label: '' },
      widget: { position: 'bottom-right', mode: 'floating', width: '380px', height: '580px' }
    },
    features: { vision: true, light_meter: true, orders: true, quick_actions: true, white_label: false },
    seasonal: {
      enabled: true, auto_switch: true, current_override: null,
      themes: {
        halloween:  { enabled: true, start: '10-15', end: '11-01' },
        christmas:  { enabled: true, start: '12-01', end: '12-31' },
        valentines: { enabled: true, start: '02-01', end: '02-15' },
        spring:     { enabled: true, start: '03-20', end: '06-20' },
        summer:     { enabled: true, start: '06-21', end: '09-22' }
      }
    }
  };
}

return [{ json: config }];
